package main.java.org.example;import com.gamestudio.tictactoe.Board;import java.util.Scanner;public class TicTacToe {    private Board board;    private char currentPlayer;    private boolean gameOver;    public TicTacToe() {        board = new Board();        currentPlayer = 'X';        gameOver = false;    }    public void playTurn() {        Scanner scanner = new Scanner(System.in);        int row, col;        System.out.println("Current Player: " + currentPlayer);        while (true) {            System.out.print("row (0-2): ");            row = scanner.nextInt();            System.out.print("column (0-2): ");            col = scanner.nextInt();            if (board.placeSymbol(row, col, currentPlayer)) {                board.printBoard();                if (board.hasWon(currentPlayer)) {                    System.out.println("Game over! Player " + currentPlayer + " has won!");                    gameOver = true;                } else if (board.isDraw()) {                    System.out.println("Game over! It is a draw!");                    gameOver = true;                } else {                    switchPlayer();                }                break;            } else {                System.out.println("This move is invalid or the cell is already taken! Try again.");            }        }    }    private void switchPlayer() {        currentPlayer = (currentPlayer == 'X') ? 'O' : 'X';    }    public static void main(String[] args) {        TicTacToe game = new TicTacToe();        System.out.println("--- TicTacToe Game Started ---");        game.board.printBoard();        while (!game.gameOver) {            game.playTurn();        }    }}